// ── Logo ──────────────────────────────────────────────────────────────────────
const LOGO_SRC = "data:image/png;base64,";

function MissyLogo({ size = 56 }) {
  const glowSize = size * 1.1;
  return (
    /* Outer container is larger to give glow room — but glow only expands UP and RIGHT, not left */
    <div style={{ position:"relative", width:size, height:size, flexShrink:0, overflow:"visible" }}>
      {/* Static soft pink glow — centered on logo, fades so left edge is soft */}
      <div style={{
        position:"absolute",
        top:"50%", left:"50%",
        transform:"translate(-50%,-50%)",
        width:glowSize, height:glowSize,
        borderRadius:"50%",
        background:"radial-gradient(circle, rgba(232,68,90,0.28) 0%, rgba(255,140,160,0.10) 50%, rgba(255,180,200,0) 70%)",
        pointerEvents:"none", zIndex:0
      }}/>
      {/* M logo scales small → big → small */}
      <img
        src={LOGO_SRC}
        alt="Missy"
        style={{
          width:size, height:size,
          objectFit:"contain",
          position:"relative", zIndex:1,
          animation:"missyPulse 2.6s ease-in-out infinite",
          transformOrigin:"center center",
        }}
      />
    </div>
  );
}

