// ── EARNINGS TAB ─────────────────────────────────────────────────────────────
const EARNINGS_DATA = [
  { customer:"林詩雅",  service:"Gel Nails",           amount:280, date:"2025-03-09" },
  { customer:"陳曉彤",  service:"Lash Lift",            amount:380, date:"2025-03-09" },
  { customer:"美玲",    service:"Nail Art (Full Set)",  amount:380, date:"2025-03-09" },
  { customer:"王凱莉",  service:"Classic Lashes",       amount:480, date:"2025-03-09" },
  { customer:"張珍妮",  service:"Nail Removal + Gel",   amount:220, date:"2025-03-09" },
  { customer:"袁詩筠",  service:"Volume Lashes",        amount:680, date:"2025-03-08" },
  { customer:"方美儀",  service:"Gel Nails + Nail Art", amount:580, date:"2025-03-08" },
  { customer:"林詩雅",  service:"Gel Nails",            amount:280, date:"2025-03-07" },
  { customer:"陳曉彤",  service:"Lash Lift",            amount:380, date:"2025-03-06" },
  { customer:"Kelly",   service:"Classic Lashes",       amount:480, date:"2025-03-05" },
  { customer:"Jenny",   service:"Gel Nails",            amount:280, date:"2025-03-04" },
  { customer:"美玲",    service:"Volume Lashes",        amount:680, date:"2025-03-03" },
];

function EarningsTab({ t }) {
  const today = "2025-03-09";
  const todayEarnings = EARNINGS_DATA.filter(r => r.date === today).reduce((s,r) => s+r.amount, 0);
  const mtdEarnings   = EARNINGS_DATA.reduce((s,r) => s+r.amount, 0);
  const momChange     = +8.3;

  const exportCSV = () => {
    const header = "Customer,Service,Amount (HKD),Date";
    const rows = EARNINGS_DATA.map(r => `${r.customer},${r.service},${r.amount},${r.date}`);
    const blob = new Blob([header + "\n" + rows.join("\n")], { type:"text/csv;charset=utf-8;" });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement("a");
    a.href = url; a.download = "missy-earnings.csv"; a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div style={{ padding:"16px", background:C.bg, minHeight:"100%" }} className="animate-slide">

      {/* Header */}
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
        <div style={{ fontSize:13, fontWeight:700, color:C.t2, letterSpacing:0.5 }}>{t("earningsOverview")}</div>
        <button onClick={exportCSV} style={{
          display:"flex", alignItems:"center", gap:6, padding:"7px 14px", borderRadius:20,
          border:`1.5px solid ${C.border}`, background:C.card, cursor:"pointer",
          fontSize:12, fontWeight:600, color:C.t2
        }}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none">
            <path d="M12 3v13M7 11l5 5 5-5" stroke={C.t2} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
            <path d="M4 20h16" stroke={C.t2} strokeWidth="2" strokeLinecap="round"/>
          </svg>
          {t("exportExcel")}
        </button>
      </div>

      {/* KPI cards */}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12, marginBottom:16 }}>
        <div style={{ background:C.card, borderRadius:20, padding:"20px 16px", boxShadow:"0 1px 6px rgba(0,0,0,0.06)" }}>
          <div style={{ fontSize:11, color:C.t3, marginBottom:6, fontWeight:600 }}>{t("todayEarnings")}</div>
          <div style={{ fontSize:26, fontWeight:800, color:C.t1 }}>
            <span style={{ fontSize:13, fontWeight:600, color:C.t3 }}>HK$</span>{todayEarnings.toLocaleString()}
          </div>
          <div style={{ fontSize:11, color:C.t3, marginTop:4 }}>
            {EARNINGS_DATA.filter(r=>r.date===today).length} {t("services")}
          </div>
        </div>
        <div style={{ background:C.card, borderRadius:20, padding:"20px 16px", boxShadow:"0 1px 6px rgba(0,0,0,0.06)" }}>
          <div style={{ fontSize:11, color:C.t3, marginBottom:6, fontWeight:600 }}>{t("mtdEarnings")}</div>
          <div style={{ fontSize:26, fontWeight:800, color:C.red }}>
            <span style={{ fontSize:13, fontWeight:600, color:C.t3 }}>HK$</span>{mtdEarnings.toLocaleString()}
          </div>
          <div style={{ display:"flex", alignItems:"center", gap:4, marginTop:4 }}>
            <span style={{ fontSize:10, fontWeight:700, color:C.green, background:C.greenLight, padding:"2px 6px", borderRadius:8 }}>
              ▲ {momChange}% MoM
            </span>
          </div>
        </div>
      </div>

      {/* Transaction list */}
      <div style={{ fontSize:11, fontWeight:700, color:C.t3, letterSpacing:1, marginBottom:10 }}>{t("transactions")}</div>
      <div style={{ background:C.card, borderRadius:16, overflow:"hidden", marginBottom:20 }}>
        {EARNINGS_DATA.map((r, i) => (
          <div key={i} style={{
            display:"flex", alignItems:"center", padding:"12px 16px",
            borderBottom: i < EARNINGS_DATA.length-1 ? `1px solid ${C.border}` : "none"
          }}>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:13, fontWeight:600, color:C.t1 }}>{r.customer}</div>
              <div style={{ fontSize:11, color:C.t3, marginTop:1 }}>{r.service} · {r.date}</div>
            </div>
            <div style={{ fontSize:14, fontWeight:700, color:C.t1 }}>HK${r.amount}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── App ───────────────────────────────────────────────────────────────────────
export default function MissySalonApp() {
  const [lang, setLang]       = useState("zh");
  const [tab, setTab]         = useState("today");
  const [missyOn, setMissyOn] = useState(true);

  const t = (key) => T[key]?.[lang] ?? T[key]?.["zh"] ?? key;

  return (
    <>
      <style>{globalStyle}</style>
      <div style={{
        maxWidth:390, margin:"0 auto", background:C.bg,
        minHeight:"100vh", display:"flex", flexDirection:"column",
        fontFamily:"'DM Sans','Noto Sans HK',sans-serif",
        boxShadow:"0 0 40px rgba(0,0,0,0.12)"
      }}>
        <Header lang={lang} setLang={setLang} missyOn={missyOn} setMissyOn={setMissyOn} t={t} />

        <div style={{ flex:1, overflowY:"auto" }}>
          {tab === "today"    && <TodayTab    t={t} lang={lang} />}
          {tab === "calendar" && <CalendarTab t={t} />}
          {tab === "messages" && <MessagesTab t={t} lang={lang} />}
          {tab === "vip"      && <VipTab      t={t} />}
          {tab === "settings" && <SettingsTab t={t} lang={lang} setLang={setLang} />}
        </div>

        <BottomNav tab={tab} setTab={setTab} t={t} />
      </div>
    </>
  );
}
